1	#include "editor.h"
2	#include "terminal.h"
3	#include "highlighters.h"
4	#include "fuzzy.h"
5	#include <filesystem>
6	#include <algorithm>
7	#include <cstdlib>
8	#include <sstream>
9	#include <unistd.h>
10	#include <signal.h>
11	
12	namespace fs = std::filesystem;
13	
14	static std::string recentDbPath() {
15	    const char* home = std::getenv("HOME");
16	    std::string dir = home ? std::string(home) + "/.local/share/nanoclone" : "/tmp/nanoclone";
17	    fs::create_directories(dir);
18	    return dir + "/recent.txt";
19	}
20	
21	// ── Lifecycle ──────────────────────────────────────────────────────────────
22	
23	Editor::Editor()
24	    : filePanel_(fs::current_path().string()), db_(recentDbPath()) {
25	    Term::enableRawMode();
26	    Term::hideCursor();
27	    Term::clearScreen();
28	    refreshSize();
29	    newBuffer();
30	}
31	
32	Editor::~Editor() {
33	    Term::clearScreen();
34	    Term::moveCursor(0, 0);
35	    Term::showCursor();
36	    Term::disableRawMode();
37	}
38	
39	void Editor::refreshSize() {
40	    Term::getSize(termRows_, termCols_);
41	}
42	
43	// ── Public API ─────────────────────────────────────────────────────────────
44	
45	void Editor::openFile(const std::string& path) {
46	    for (int i = 0; i < (int)buffers_.size(); ++i) {
47	        if (buffers_[i]->filename() == path) { switchBuffer(i); return; }
48	    }
49	    auto buf = std::make_unique<Buffer>();
50	    if (!buf->load(path)) { setStatus("Error: cannot open " + path); return; }
51	    buf->setHighlighter(makeHighlighter(path));
52	    buffers_.push_back(std::move(buf));
53	    currentBuf_ = (int)buffers_.size() - 1;
54	    db_.addRecentFile(path);
55	}
56	
57	void Editor::run() {
58	    while (!shouldQuit_) {
59	        refreshSize();
60	        render();
61	        int key = Term::readKey();
62	        if (key == Key::RESIZE) continue;
63	        handleKey(key);
64	    }
65	}
66	
67	// ── Helpers ────────────────────────────────────────────────────────────────
68	
69	Buffer* Editor::currentBuffer() {
70	    if (buffers_.empty()) return nullptr;
71	    return buffers_[currentBuf_].get();
72	}
73	
74	int Editor::editRows() const     { return std::max(1, termRows_ - 2); }
75	int Editor::editStartCol() const { return panelVisible_ ? kPanelWidth + 1 : 0; }
76	int Editor::editCols() const     { return std::max(1, termCols_ - editStartCol()); }
77	void Editor::setStatus(const std::string& msg) { statusMsg_ = msg; }
78	
79	std::string Editor::pad(const std::string& s, int width) {
80	    if (width <= 0) return "";
81	    if ((int)s.size() >= width) return s.substr(0, width);
82	    return s + std::string(width - s.size(), ' ');
83	}
84	
85	std::string Editor::truncLeft(const std::string& s, int width) {
86	    if ((int)s.size() <= width) return s;
87	    return ".." + s.substr(s.size() - (width - 2));
88	}
89	
90	// ── Buffer management ──────────────────────────────────────────────────────
91	
92	void Editor::newBuffer() {
93	    buffers_.push_back(std::make_unique<Buffer>());
94	    currentBuf_ = (int)buffers_.size() - 1;
95	}
96	
97	void Editor::closeCurrentBuffer() {
98	    auto* buf = currentBuffer();
99	    if (buf && buf->isDirty()) { mode_ = Mode::ConfirmQuit; return; }
100	    doCloseCurrentBuffer();
101	}
102	
103	void Editor::doCloseCurrentBuffer() {
104	    if (buffers_.empty()) return;
105	    buffers_.erase(buffers_.begin() + currentBuf_);
106	    if (buffers_.empty()) { shouldQuit_ = true; return; }
107	    if (currentBuf_ >= (int)buffers_.size()) currentBuf_ = (int)buffers_.size() - 1;
108	}
109	
110	void Editor::switchBuffer(int idx) {
111	    if (idx >= 0 && idx < (int)buffers_.size()) currentBuf_ = idx;
112	}
113	
114	void Editor::nextBuffer() {
115	    if (!buffers_.empty()) currentBuf_ = (currentBuf_ + 1) % (int)buffers_.size();
116	}
117	
118	void Editor::prevBuffer() {
119	    if (!buffers_.empty())
120	        currentBuf_ = (currentBuf_ - 1 + (int)buffers_.size()) % (int)buffers_.size();
121	}
122	
123	// ── Rendering ──────────────────────────────────────────────────────────────
124	
125	void Editor::render() {
126	    std::string out;
127	    out.reserve(termRows_ * termCols_ * 4);
128	
129	    // Move to top-left, hide cursor during redraw
130	    out += "\033[H";
131	
132	    // --- Tabbar (row 0) ---
133	    out += "\033[44m\033[97m";  // bg blue, fg white
134	    int x = 0;
135	    for (int i = 0; i < (int)buffers_.size() && x < termCols_; ++i) {
136	        std::string label = " " + buffers_[i]->displayName();
137	        if (buffers_[i]->isDirty()) label += '*';
138	        label += ' ';
139	        int avail = termCols_ - x;
140	        if ((int)label.size() > avail) label.resize(avail);
141	
142	        if (i == currentBuf_) {
143	            out += "\033[0m\033[1m\033[47m\033[30m";  // bold, bg white, fg black
144	            out += label;
145	            out += "\033[0m\033[44m\033[97m";
146	        } else if (buffers_[i]->isDirty()) {
147	            out += "\033[33m" + label + "\033[97m";   // yellow for dirty
148	        } else {
149	            out += label;
150	        }
151	        x += (int)label.size();
152	    }
153	    // fill rest of tabbar
154	    if (x < termCols_) out += std::string(termCols_ - x, ' ');
155	    out += "\033[0m";
156	
157	    // --- Panel + Edit area (rows 1 .. termRows-2) ---
158	    for (int r = 0; r < editRows(); ++r) {
159	        // Position at start of this row
160	        out += "\033[" + std::to_string(r + 2) + ";1H";
161	
162	        // Panel column
163	        if (panelVisible_) {
164	            out += "\033[44m\033[97m";  // bg blue, fg white
165	            if (r == 0) {
166	                // header: current path
167	                out += pad(truncLeft(filePanel_.currentPath(), kPanelWidth), kPanelWidth);
168	            } else {
169	                const auto& entries = filePanel_.entries();
170	                int idx = filePanel_.scrollOffset() + (r - 1);
171	                if (idx < (int)entries.size()) {
172	                    const auto& entry = entries[idx];
173	                    bool isSel = (idx == filePanel_.selected()) && (mode_ == Mode::FilePanel);
174	                    std::string name = entry.name;
175	                    if ((int)name.size() >= kPanelWidth) name = name.substr(0, kPanelWidth - 1) + '>';
176	
177	                    if (isSel) {
178	                        out += "\033[0m\033[46m\033[30m\033[1m";  // bg cyan, fg black, bold
179	                        out += pad(name, kPanelWidth);
180	                        out += "\033[0m";
181	                    } else if (entry.isDir) {
182	                        out += "\033[36m";  // fg cyan
183	                        out += pad(name, kPanelWidth);
184	                        out += "\033[97m";
185	                    } else {
186	                        out += "\033[0m\033[44m\033[97m";
187	                        out += pad(name, kPanelWidth);
188	                    }
189	                } else {
190	                    out += std::string(kPanelWidth, ' ');
191	                }
192	            }
193	            out += "\033[0m";
194	            // Separator
195	            out += "\033[" + std::to_string(r + 2) + ";" + std::to_string(kPanelWidth + 1) + "H";
196	            out += "\033[90m\342\224\202\033[0m";  // │ in dark gray
197	        }
198	
199	        // Edit area
200	        int editCol = editStartCol() + 1;  // 1-based for ANSI
201	        out += "\033[" + std::to_string(r + 2) + ";" + std::to_string(editCol) + "H";
202	
203	        auto* buf = currentBuffer();
204	        if (buf) {
205	            const auto& lines = buf->lines();
206	            int lineIdx = buf->scrollRow() + r;
207	            if (lineIdx < (int)lines.size()) {
208	                const std::string& line = lines[lineIdx];
209	                auto* hl = buf->highlighter();
210	                if (hl) {
211	                    auto spans = hl->highlight(line, lineIdx);
212	                    out += renderHighlighted(line, spans, buf->scrollCol(), editCols());
213	                } else {
214	                    int sc = buf->scrollCol();
215	                    std::string visible;
216	                    if (sc < (int)line.size())
217	                        visible = line.substr(sc, editCols());
218	                    out += visible;
219	                    int rem = editCols() - (int)visible.size();
220	                    if (rem > 0) out += std::string(rem, ' ');
221	                }
222	            } else {
223	                out += std::string(editCols(), ' ');
224	            }
225	        } else {
226	            if (r == 0)
227	                out += pad("  ^N New   ^O Panel   ^R Recent files", editCols());
228	            else
229	                out += std::string(editCols(), ' ');
230	        }
231	    }
232	
233	    // --- Recent files overlay ---
234	    if (mode_ == Mode::RecentFiles && !recentFiles_.empty()) {
235	        int ow = std::min(termCols_ - 4, 62);
236	        int oh = std::min((int)recentFiles_.size() + 2, termRows_ - 4);
237	        int oy = (termRows_ - oh) / 2;
238	        int ox = (termCols_ - ow) / 2;
239	
240	        for (int r = 0; r < oh; ++r) {
241	            out += "\033[" + std::to_string(oy + r + 1) + ";" + std::to_string(ox + 1) + "H";
242	            out += "\033[43m\033[30m";  // bg yellow, fg black
243	            if (r == 0) {
244	                out += pad(" Recent Files", ow);
245	            } else if (r == oh - 1) {
246	                out += std::string(ow, ' ');
247	            } else {
248	                int idx = r - 1;
249	                bool sel = (idx == recentSelected_);
250	                std::string path = recentFiles_[idx];
251	                if ((int)path.size() > ow - 4) path = truncLeft(path, ow - 4);
252	                std::string row = "  " + path;
253	                if (sel) {
254	                    out += "\033[0m\033[47m\033[30m\033[1m";
255	                    out += pad(row, ow);
256	                    out += "\033[0m\033[43m\033[30m";
257	                } else {
258	                    out += pad(row, ow);
259	                }
260	            }
261	            out += "\033[0m";
262	        }
263	    }
264	
265	    // --- Fuzzy finder overlay ---
266	    if (mode_ == Mode::FuzzyFinder) {
267	        renderFuzzyOverlay(out);
268	    }
269	
270	    // --- Status bar (last row) ---
271	    out += "\033[" + std::to_string(termRows_) + ";1H";
272	    out += "\033[47m\033[30m";  // bg white, fg black
273	
274	    if (!statusMsg_.empty()) {
275	        out += "\033[1m" + pad(statusMsg_, termCols_) + "\033[0m";
276	    } else {
277	        auto hint = [&](const std::string& key, const std::string& desc) {
278	            return "\033[34m\033[1m" + key + "\033[0m\033[47m\033[30m " + desc + "  ";
279	        };
280	
281	        std::string bar;
282	        switch (mode_) {
283	            case Mode::Edit:
284	                bar += hint("^X", "Exit") + hint("^S", "Save") + hint("^O", "Panel")
285	                     + hint("^P", "Files") + hint("^F", "Find") + hint("^N", "New")
286	                     + hint("^R", "Recent") + hint("^A/^E", "Tabs");
287	                break;
288	            case Mode::FilePanel:
289	                bar += hint("Enter", "Open") + hint("Esc", "Back");
290	                break;
291	            case Mode::Find:
292	                bar = "\033[47m\033[30mFind: " + inputStr_ + "_";
293	                break;
294	            case Mode::SaveAs:
295	                bar = "\033[47m\033[30mSave as: " + inputStr_ + "_";
296	                break;
297	            case Mode::ConfirmQuit:
298	                bar = "\033[47m\033[30m\033[1mUnsaved changes \033[0m\033[47m\033[30m"
299	                      "— (S)ave  (D)iscard  (C)ancel";
300	                break;
301	            case Mode::RecentFiles:
302	                bar = "\033[47m\033[30mUp/Down = select   Enter = open   Esc = cancel";
303	                break;
304	            case Mode::FuzzyFinder:
305	                bar = "\033[47m\033[30mType to search   Up/Down = select   Enter = open   Esc = cancel";
306	                break;
307	        }
308	        // strip ANSI for length calc is complex; just pad with spaces roughly
309	        out += bar + "\033[K";
310	    }
311	    out += "\033[0m";
312	
313	    // Position cursor
314	    if (mode_ == Mode::Edit) {
315	        if (auto* buf = currentBuffer()) {
316	            int cy = buf->cursorRow() - buf->scrollRow() + 2;  // +2: tabbar offset (1-based)
317	            int cx = buf->cursorCol() - buf->scrollCol() + editStartCol() + 1;
318	            out += "\033[" + std::to_string(cy) + ";" + std::to_string(cx) + "H";
319	            out += "\033[?25h";  // show cursor
320	        }
321	    } else if (mode_ == Mode::Find || mode_ == Mode::SaveAs) {
322	        int prefix = (mode_ == Mode::Find) ? 6 : 9;
323	        int cx = std::min(prefix + (int)inputStr_.size() + 1, termCols_);
324	        out += "\033[" + std::to_string(termRows_) + ";" + std::to_string(cx) + "H";
325	        out += "\033[?25h";
326	    } else if (mode_ == Mode::FuzzyFinder) {
327	        int ow = std::min(termCols_ - 4, 72);
328	        int oh = std::max(5, std::min((int)fuzzyResults_.size() + 3, termRows_ - 4));
329	        int oy = (termRows_ - oh) / 2;
330	        int ox = (termCols_ - ow) / 2;
331	        // cursor after " > " prefix (3 chars) + query
332	        int cx = ox + 1 + 3 + (int)inputStr_.size();
333	        int cy = oy + 1;
334	        out += "\033[" + std::to_string(cy) + ";" + std::to_string(cx) + "H";
335	        out += "\033[?25h";
336	    } else {
337	        out += "\033[?25l";  // hide cursor
338	    }
339	
340	    if (write(STDOUT_FILENO, out.c_str(), out.size()) < 0) {}
341	}
