358	void Editor::handleEditKey(int key) {
359	    auto* buf = currentBuffer();
360	    switch (key) {
361	        case Key::ARROW_UP:    if (buf) buf->moveCursor(-1, 0); break;
362	        case Key::ARROW_DOWN:  if (buf) buf->moveCursor( 1, 0); break;
363	        case Key::ARROW_LEFT:  if (buf) buf->moveCursor(0, -1); break;
364	        case Key::ARROW_RIGHT: if (buf) buf->moveCursor(0,  1); break;
365	        case Key::HOME:        if (buf) buf->moveCursorHome();  break;
366	        case Key::END:         if (buf) buf->moveCursorEnd();   break;
367	        case Key::PAGE_UP:     if (buf) buf->moveCursorPageUp(editRows());   break;
368	        case Key::PAGE_DOWN:   if (buf) buf->moveCursorPageDown(editRows()); break;
369	        case Key::BACKSPACE:   if (buf) buf->deleteCharBefore(); break;
370	        case Key::DEL:         if (buf) buf->deleteCharAfter();  break;
371	        case Key::ENTER:       if (buf) buf->insertNewline();    break;
372	        case Key::CTRL_S:      saveCurrent();       break;
373	        case Key::CTRL_X:      closeCurrentBuffer(); break;
374	        case Key::CTRL_O:      togglePanel();       break;
375	        case Key::CTRL_N:      newBuffer();         break;
376	        case Key::CTRL_F:      startFind();         break;
377	        case Key::CTRL_R:      startRecentFiles();   break;
378	        case Key::CTRL_A:      prevBuffer();         break;
379	        case Key::CTRL_E:      nextBuffer();         break;
380	        case Key::CTRL_P:      startFuzzyFinder();   break;
381	        default:
382	            if (buf && key >= 32 && key < 256)
383	                buf->insertChar((char)key);
384	            break;
385	    }
386	    if (buf) buf->updateScroll(editRows(), editCols());
387	}
