575	static std::string fuzzyEntryLine(const std::string& path, int width, bool selected) {
576	    size_t slash = path.rfind('/');
577	    std::string base = (slash == std::string::npos) ? path : path.substr(slash + 1);
578	    std::string dir  = (slash == std::string::npos) ? "" : path.substr(0, slash);
579	
580	    int visLen = 2 + (int)base.size() + (dir.empty() ? 0 : 2 + (int)dir.size());
581	    int pad    = std::max(0, width - visLen);
582	
583	    std::string out;
584	    if (selected) {
585	        out += "\033[0m\033[46m\033[30m\033[1m  " + base;
586	        if (!dir.empty()) out += "  " + dir;
587	        out += std::string(pad, ' ');
588	        out += "\033[0m";
589	    } else {
590	        out += "  \033[1m" + base + "\033[0m";
591	        if (!dir.empty()) out += "  \033[90m" + dir + "\033[0m";
592	        out += std::string(pad, ' ');
593	    }
594	    return out;
595	}
596	
597	void Editor::renderFuzzyOverlay(std::string& out) {
598	    int ow = std::min(termCols_ - 4, 72);
599	    // title(1) + sep(1) + results + footer(1), min 5 rows
600	    int listH = std::min((int)fuzzyResults_.size(), 15);
601	    int oh    = std::max(5, std::min(listH + 3, termRows_ - 4));
602	    listH     = oh - 3;
603	    int oy    = (termRows_ - oh) / 2;
604	    int ox    = (termCols_ - ow) / 2;
605	
606	    // Adjust scroll so selected is visible
607	    if (fuzzyScroll_ > fuzzySelected_) fuzzyScroll_ = fuzzySelected_;
608	    if (fuzzyScroll_ + listH <= fuzzySelected_)
609	        fuzzyScroll_ = fuzzySelected_ - listH + 1;
610	
611	    for (int r = 0; r < oh; ++r) {
612	        out += "\033[" + std::to_string(oy + r + 1) + ";"
613	             + std::to_string(ox + 1) + "H";
614	
615	        if (r == 0) {
616	            out += "\033[44m\033[97m";
617	            std::string title = " > " + inputStr_;
618	            if ((int)title.size() < ow) title += std::string(ow - title.size(), ' ');
619	            else title.resize(ow);
620	            out += title + "\033[0m";
621	        } else if (r == 1) {
622	            out += "\033[90m" + std::string(ow, '-') + "\033[0m";
623	        } else if (r == oh - 1) {
624	            out += "\033[90m";
625	            std::string footer = " " + std::to_string(fuzzyResults_.size()) + " files";
626	            if ((int)footer.size() < ow) footer += std::string(ow - footer.size(), ' ');
627	            out += footer + "\033[0m";
628	        } else {
629	            int idx = fuzzyScroll_ + (r - 2);
630	            if (idx < (int)fuzzyResults_.size()) {
631	                out += fuzzyEntryLine(fuzzyResults_[idx].second, ow,
632	                                      idx == fuzzySelected_);
633	            } else {
634	                out += std::string(ow, ' ');
635	            }
636	        }
637	    }
638	}
