7	namespace fs = std::filesystem;
8	
9	// ── Generic scanner ────────────────────────────────────────────────────────
10	
11	struct ScanConfig {
12	    std::unordered_set<std::string> keywords;
13	    std::unordered_set<std::string> types;
14	    std::string lineComment;          // e.g. "//" or "#"
15	    std::string blockOpen;            // e.g. "/*"
16	    std::string blockClose;           // e.g. "*/"
17	    bool hasPreproc = false;          // C-style # lines
18	    bool hasDecorator = false;        // Python @
19	    char extraStringQuote = 0;        // 0 = none (backtick for JS)
20	};
21	
22	static bool startsWith(const std::string& s, size_t pos, const std::string& prefix) {
23	    if (prefix.empty()) return false;
24	    return s.compare(pos, prefix.size(), prefix) == 0;
25	}
26	
27	static std::vector<ColorSpan> scanGeneric(const std::string& line, const ScanConfig& cfg) {
28	    std::vector<ColorSpan> spans;
29	    size_t n = line.size();
30	    size_t i = 0;
31	
32	    // Preprocessor line (C/C++: starts with optional space then #)
33	    if (cfg.hasPreproc) {
34	        size_t j = 0;
35	        while (j < n && line[j] == ' ') ++j;
36	        if (j < n && line[j] == '#') {
37	            spans.push_back({0, (int)n, HL::PREPROC});
38	            return spans;
39	        }
40	    }
41	
42	    while (i < n) {
43	        // Block comment
44	        if (!cfg.blockOpen.empty() && startsWith(line, i, cfg.blockOpen)) {
45	            size_t start = i;
46	            i += cfg.blockOpen.size();
47	            while (i < n && !startsWith(line, i, cfg.blockClose)) ++i;
48	            if (i < n) i += cfg.blockClose.size();
49	            spans.push_back({(int)start, (int)(i - start), HL::COMMENT});
50	            continue;
51	        }
52	
53	        // Line comment
54	        if (!cfg.lineComment.empty() && startsWith(line, i, cfg.lineComment)) {
55	            spans.push_back({(int)i, (int)(n - i), HL::COMMENT});
56	            break;
57	        }
58	
59	        // Strings: double quote
60	        if (line[i] == '"') {
61	            size_t start = i++;
62	            while (i < n && !(line[i] == '"' && line[i-1] != '\\')) ++i;
63	            if (i < n) ++i;
64	            spans.push_back({(int)start, (int)(i - start), HL::STRING});
65	            continue;
66	        }
67	
68	        // Strings: single quote
69	        if (line[i] == '\'') {
70	            size_t start = i++;
71	            while (i < n && !(line[i] == '\'' && line[i-1] != '\\')) ++i;
72	            if (i < n) ++i;
73	            spans.push_back({(int)start, (int)(i - start), HL::STRING});
74	            continue;
75	        }
76	
77	        // Extra string quote (e.g. backtick for JS)
78	        if (cfg.extraStringQuote && line[i] == cfg.extraStringQuote) {
79	            size_t start = i++;
80	            while (i < n && line[i] != cfg.extraStringQuote) ++i;
81	            if (i < n) ++i;
82	            spans.push_back({(int)start, (int)(i - start), HL::STRING});
83	            continue;
84	        }
85	
86	        // Decorator (Python @name)
87	        if (cfg.hasDecorator && line[i] == '@') {
88	            size_t start = i++;
89	            while (i < n && (std::isalnum(line[i]) || line[i] == '_' || line[i] == '.')) ++i;
90	            spans.push_back({(int)start, (int)(i - start), HL::PREPROC});
91	            continue;
92	        }
93	
94	        // Number
95	        if (std::isdigit(line[i]) || (line[i] == '.' && i + 1 < n && std::isdigit(line[i+1]))) {
96	            size_t start = i;
97	            while (i < n && (std::isalnum(line[i]) || line[i] == '.' || line[i] == '_')) ++i;
98	            spans.push_back({(int)start, (int)(i - start), HL::NUMBER});
99	            continue;
100	        }
101	
102	        // Identifier / keyword
103	        if (std::isalpha(line[i]) || line[i] == '_') {
104	            size_t start = i;
105	            while (i < n && (std::isalnum(line[i]) || line[i] == '_')) ++i;
106	            std::string word = line.substr(start, i - start);
107	            if (cfg.keywords.count(word))
108	                spans.push_back({(int)start, (int)(i - start), HL::KEYWORD});
109	            else if (cfg.types.count(word))
110	                spans.push_back({(int)start, (int)(i - start), HL::TYPE});
111	            continue;
112	        }
113	
114	        ++i;
115	    }
116	
117	    return spans;
118	}
