237	// ── HTML ───────────────────────────────────────────────────────────────────
238	
239	class HtmlHighlighter : public SyntaxHighlighter {
240	public:
241	    std::vector<ColorSpan> highlight(const std::string& line, int) override {
242	        std::vector<ColorSpan> spans;
243	        size_t n = line.size();
244	        size_t i = 0;
245	
246	        while (i < n) {
247	            // Comment <!-- ... -->
248	            if (i + 3 < n && line.substr(i, 4) == "<!--") {
249	                size_t start = i;
250	                i += 4;
251	                while (i + 2 < n && line.substr(i, 3) != "-->") ++i;
252	                if (i + 2 < n) i += 3;
253	                spans.push_back({(int)start, (int)(i - start), HL::COMMENT});
254	                continue;
255	            }
256	
257	            // Tag
258	            if (line[i] == '<') {
259	                ++i;
260	                bool closing = (i < n && line[i] == '/');
261	                if (closing) ++i;
262	
263	                // Tag name
264	                size_t nameStart = i;
265	                while (i < n && (std::isalnum(line[i]) || line[i] == '-' || line[i] == ':')) ++i;
266	                if (i > nameStart)
267	                    spans.push_back({(int)nameStart, (int)(i - nameStart), HL::TAG});
268	
269	                // Attributes until >
270	                while (i < n && line[i] != '>') {
271	                    while (i < n && line[i] == ' ') ++i;
272	                    if (i < n && line[i] == '>') break;
273	
274	                    // attribute name
275	                    size_t attrStart = i;
276	                    while (i < n && line[i] != '=' && line[i] != ' ' && line[i] != '>') ++i;
277	                    if (i > attrStart)
278	                        spans.push_back({(int)attrStart, (int)(i - attrStart), HL::ATTR});
279	
280	                    if (i < n && line[i] == '=') {
281	                        ++i;
282	                        if (i < n && (line[i] == '"' || line[i] == '\'')) {
283	                            char q = line[i];
284	                            size_t valStart = i++;
285	                            while (i < n && line[i] != q) ++i;
286	                            if (i < n) ++i;
287	                            spans.push_back({(int)valStart, (int)(i - valStart), HL::STRING});
288	                        }
289	                    }
290	                }
291	                if (i < n && line[i] == '>') ++i;
292	                continue;
293	            }
294	
295	            // String outside tag (rare, but skip)
296	            ++i;
297	        }
298	
299	        return spans;
300	    }
301	
302	    bool supportsFile(const std::string& f) const override {
303	        auto ext = fs::path(f).extension().string();
304	        return ext==".html"||ext==".htm"||ext==".xhtml";
305	    }
306	};
