308	// ── CSS ────────────────────────────────────────────────────────────────────
309	
310	class CssHighlighter : public SyntaxHighlighter {
311	public:
312	    std::vector<ColorSpan> highlight(const std::string& line, int) override {
313	        std::vector<ColorSpan> spans;
314	        size_t n = line.size();
315	        size_t i = 0;
316	
317	        // Block comment
318	        if (i + 1 < n && line[i] == '/' && line[i+1] == '*') {
319	            size_t start = i;
320	            i += 2;
321	            while (i + 1 < n && !(line[i]=='*' && line[i+1]=='/')) ++i;
322	            if (i + 1 < n) i += 2;
323	            spans.push_back({(int)start, (int)(i - start), HL::COMMENT});
324	        }
325	
326	        // Check if this looks like a selector line (has { or ends before {)
327	        bool hasBrace = line.find('{') != std::string::npos;
328	        bool hasColon = line.find(':') != std::string::npos;
329	
330	        while (i < n) {
331	            // Comment
332	            if (i + 1 < n && line[i] == '/' && line[i+1] == '*') {
333	                size_t start = i; i += 2;
334	                while (i + 1 < n && !(line[i]=='*' && line[i+1]=='/')) ++i;
335	                if (i + 1 < n) i += 2;
336	                spans.push_back({(int)start, (int)(i - start), HL::COMMENT});
337	                continue;
338	            }
339	
340	            // String value
341	            if (line[i] == '"' || line[i] == '\'') {
342	                char q = line[i];
343	                size_t attrValStart = i++;
344	                while (i < n && line[i] != q) ++i;
345	                if (i < n) ++i;
346	                spans.push_back({(int)attrValStart, (int)(i - attrValStart), HL::STRING});
347	                continue;
348	            }
349	
350	            // Property name (before ':' when not a selector line)
351	            if (!hasBrace && hasColon && line[i] != ' ' && line[i] != '\t') {
352	                size_t colonPos = line.find(':', i);
353	                if (colonPos != std::string::npos) {
354	                    std::string prop = line.substr(i, colonPos - i);
355	                    // trim right
356	                    size_t end = prop.find_last_not_of(' ');
357	                    if (end != std::string::npos) {
358	                        spans.push_back({(int)i, (int)(end + 1), HL::PROPERTY});
359	                        i = colonPos + 1;
360	                        // value: color numbers and hex
361	                        while (i < n) {
362	                            while (i < n && line[i] == ' ') ++i;
363	                            if (i < n && line[i] == '#') {
364	                                size_t start = i++;
365	                                while (i < n && std::isxdigit(line[i])) ++i;
366	                                spans.push_back({(int)start, (int)(i - start), HL::NUMBER});
367	                            } else if (i < n && std::isdigit(line[i])) {
368	                                size_t start = i;
369	                                while (i < n && (std::isalnum(line[i]) || line[i] == '.')) ++i;
370	                                spans.push_back({(int)start, (int)(i - start), HL::NUMBER});
371	                            } else {
372	                                ++i;
373	                            }
374	                        }
375	                        break;
376	                    }
377	                }
378	            }
379	
380	            // Selector line — color until { as SELECTOR
381	            if (hasBrace) {
382	                size_t bracePos = line.find('{');
383	                std::string sel = line.substr(i, bracePos - i);
384	                size_t end = sel.find_last_not_of(' ');
385	                if (end != std::string::npos)
386	                    spans.push_back({(int)i, (int)(end + 1), HL::SELECTOR});
387	                i = bracePos + 1;
388	                hasBrace = false;  // only first { on line
389	                continue;
390	            }
391	
392	            ++i;
393	        }
394	
395	        return spans;
396	    }
397	
398	    bool supportsFile(const std::string& f) const override {
399	        auto ext = fs::path(f).extension().string();
400	        return ext==".css"||ext==".scss"||ext==".less";
401	    }
402	};
