404	// ── JSON ───────────────────────────────────────────────────────────────────
405	
406	class JsonHighlighter : public SyntaxHighlighter {
407	public:
408	    std::vector<ColorSpan> highlight(const std::string& line, int) override {
409	        std::vector<ColorSpan> spans;
410	        size_t n = line.size();
411	        size_t i = 0;
412	
413	        while (i < n) {
414	            while (i < n && (line[i] == ' ' || line[i] == '\t')) ++i;
415	            if (i >= n) break;
416	
417	            if (line[i] == '"') {
418	                size_t start = i++;
419	                while (i < n && !(line[i] == '"' && line[i-1] != '\\')) ++i;
420	                if (i < n) ++i;
421	                size_t end = i;
422	                // peek for ':' → this is a key
423	                size_t j = end;
424	                while (j < n && (line[j] == ' ' || line[j] == '\t')) ++j;
425	                bool isKey = (j < n && line[j] == ':');
426	                spans.push_back({(int)start, (int)(end - start),
427	                                 isKey ? HL::TYPE : HL::STRING});
428	                if (isKey) i = j + 1;
429	                continue;
430	            }
431	            if (line[i] == '-' || std::isdigit(line[i])) {
432	                size_t start = i;
433	                if (line[i] == '-') ++i;
434	                while (i < n && (std::isdigit(line[i]) || line[i] == '.' ||
435	                                  line[i] == 'e' || line[i] == 'E' ||
436	                                  line[i] == '+' || line[i] == '-')) ++i;
437	                spans.push_back({(int)start, (int)(i - start), HL::NUMBER});
438	                continue;
439	            }
440	            if (std::isalpha(line[i])) {
441	                size_t start = i;
442	                while (i < n && std::isalpha(line[i])) ++i;
443	                std::string w = line.substr(start, i - start);
444	                if (w == "true" || w == "false" || w == "null")
445	                    spans.push_back({(int)start, (int)(i - start), HL::KEYWORD});
446	                continue;
447	            }
448	            ++i;
449	        }
450	        return spans;
451	    }
452	
453	    bool supportsFile(const std::string& f) const override {
454	        return fs::path(f).extension().string() == ".json";
455	    }
456	};
