458	// ── YAML ───────────────────────────────────────────────────────────────────
459	
460	class YamlHighlighter : public SyntaxHighlighter {
461	public:
462	    std::vector<ColorSpan> highlight(const std::string& line, int) override {
463	        std::vector<ColorSpan> spans;
464	        size_t n = line.size();
465	        size_t i = 0;
466	
467	        while (i < n && (line[i] == ' ' || line[i] == '\t')) ++i;
468	        if (i >= n) return spans;
469	
470	        if (line[i] == '#') {
471	            spans.push_back({(int)i, (int)(n - i), HL::COMMENT});
472	            return spans;
473	        }
474	        if (n - i >= 3 && (line.substr(i,3) == "---" || line.substr(i,3) == "...")) {
475	            spans.push_back({(int)i, (int)(n - i), HL::KEYWORD});
476	            return spans;
477	        }
478	        if (line[i] == '-' && i+1 < n && line[i+1] == ' ') {
479	            spans.push_back({(int)i, 1, HL::KEYWORD});
480	            i += 2;
481	        }
482	        if (i < n && (line[i] == '&' || line[i] == '*')) {
483	            size_t start = i++;
484	            while (i < n && (std::isalnum(line[i]) || line[i] == '_' || line[i] == '-')) ++i;
485	            spans.push_back({(int)start, (int)(i - start), HL::PREPROC});
486	        }
487	
488	        // find colon separator for key: value
489	        size_t colonPos = std::string::npos;
490	        {
491	            bool inStr = false; char sq = 0;
492	            for (size_t j = i; j < n; ++j) {
493	                if (!inStr && (line[j] == '"' || line[j] == '\'')) { inStr = true; sq = line[j]; }
494	                else if (inStr && line[j] == sq) inStr = false;
495	                else if (!inStr && line[j] == ':' && (j+1 >= n || line[j+1] == ' ')) {
496	                    colonPos = j; break;
497	                }
498	            }
499	        }
500	
501	        if (colonPos != std::string::npos) {
502	            spans.push_back({(int)i, (int)(colonPos - i), HL::TYPE});
503	            i = colonPos + 1;
504	        }
505	
506	        while (i < n) {
507	            while (i < n && (line[i] == ' ' || line[i] == '\t')) ++i;
508	            if (i < n && (line[i] == '"' || line[i] == '\'')) {
509	                char q = line[i]; size_t start = i++;
510	                while (i < n && line[i] != q) ++i;
511	                if (i < n) ++i;
512	                spans.push_back({(int)start, (int)(i - start), HL::STRING});
513	            } else if (i < n && line[i] == '#') {
514	                spans.push_back({(int)i, (int)(n - i), HL::COMMENT});
515	                break;
516	            } else if (i < n && (std::isdigit(line[i]) || line[i] == '-')) {
517	                size_t start = i;
518	                while (i < n && (std::isdigit(line[i]) || line[i] == '.' || line[i] == '-')) ++i;
519	                spans.push_back({(int)start, (int)(i - start), HL::NUMBER});
520	            } else if (i < n && std::isalpha(line[i])) {
521	                size_t start = i;
522	                while (i < n && (std::isalnum(line[i]) || line[i] == '_')) ++i;
523	                std::string w = line.substr(start, i - start);
524	                if (w=="true"||w=="false"||w=="null"||w=="yes"||w=="no"||w=="on"||w=="off")
525	                    spans.push_back({(int)start, (int)(i - start), HL::KEYWORD});
526	                continue;
527	            } else { ++i; }
528	        }
529	        return spans;
530	    }
531	
532	    bool supportsFile(const std::string& f) const override {
533	        auto e = fs::path(f).extension().string();
534	        return e == ".yaml" || e == ".yml";
535	    }
536	};
