540	class ShellHighlighter : public SyntaxHighlighter {
541	    ScanConfig cfg_;
542	public:
543	    ShellHighlighter() {
544	        cfg_.keywords = {
545	            "if","then","else","elif","fi","for","while","do","done",
546	            "case","esac","in","function","return","exit","break","continue",
547	            "local","declare","readonly","export","unset","shift","trap",
548	            "echo","printf","read","source","eval","exec","alias","cd",
549	            "true","false","test",
550	        };
551	        cfg_.lineComment = "#";
552	    }
553	
554	    std::vector<ColorSpan> highlight(const std::string& line, int) override {
555	        auto spans = scanGeneric(line, cfg_);
556	        // $VAR and ${VAR}
557	        size_t n = line.size();
558	        for (size_t i = 0; i < n; ++i) {
559	            if (line[i] != '$') continue;
560	            size_t start = i++;
561	            if (i < n && line[i] == '{') {
562	                while (i < n && line[i] != '}') ++i;
563	                if (i < n) ++i;
564	            } else if (i < n && (std::isalpha(line[i]) || line[i] == '_' ||
565	                                   line[i] == '?' || line[i] == '#' ||
566	                                   line[i] == '@' || std::isdigit(line[i]))) {
567	                while (i < n && (std::isalnum(line[i]) || line[i] == '_')) ++i;
568	            } else { continue; }
569	            spans.push_back({(int)start, (int)(i - start), HL::TYPE});
570	        }
571	        return spans;
572	    }
