583	// ── Makefile ───────────────────────────────────────────────────────────────
584	
585	class MakefileHighlighter : public SyntaxHighlighter {
586	public:
587	    std::vector<ColorSpan> highlight(const std::string& line, int) override {
588	        std::vector<ColorSpan> spans;
589	        size_t n = line.size();
590	        if (n == 0) return spans;
591	
592	        // Comment
593	        if (line[0] == '#') { spans.push_back({0,(int)n,HL::COMMENT}); return spans; }
594	
595	        // Directives: ifeq, include, define, ...
596	        static const std::vector<std::string> directives = {
597	            "include","ifeq","ifneq","ifdef","ifndef","else","endif",
598	            "define","endef","override","export","unexport","vpath",
599	        };
600	        for (const auto& d : directives) {
601	            if (line.compare(0, d.size(), d) == 0 &&
602	                (d.size() == n || line[d.size()] == ' ' || line[d.size()] == '\t')) {
603	                spans.push_back({0,(int)d.size(),HL::KEYWORD});
604	                break;
605	            }
606	        }
607	
608	        // $(VAR) / ${VAR} and automatic vars $@ $< $^
609	        for (size_t i = 0; i < n; ++i) {
610	            if (line[i] != '$') continue;
611	            size_t start = i++;
612	            if (i < n && (line[i] == '(' || line[i] == '{')) {
613	                char close = (line[i] == '(') ? ')' : '}';
614	                while (i < n && line[i] != close) ++i;
615	                if (i < n) ++i;
616	                spans.push_back({(int)start,(int)(i-start),HL::TYPE});
617	            } else if (i < n && (line[i]=='@'||line[i]=='<'||line[i]=='^'||line[i]=='*')) {
618	                spans.push_back({(int)start, 2, HL::PREPROC});
619	                ++i;
620	            }
621	        }
622	
623	        // Variable assignment: VAR = / := / ?= / +=
624	        if (line[0] != '\t') {
625	            size_t j = 0;
626	            while (j < n && (std::isalnum(line[j]) || line[j]=='_' || line[j]=='.')) ++j;
627	            size_t k = j;
628	            while (k < n && line[k] == ' ') ++k;
629	            if (k < n && (line[k]=='='||((line[k]==':'||line[k]=='?'||line[k]=='+')
630	                           && k+1 < n && line[k+1]=='='))) {
631	                if (j > 0) spans.push_back({0,(int)j,HL::TYPE});
632	                return spans;
633	            }
634	            // Target rule: target:
635	            size_t col = line.find(':');
636	            if (col != std::string::npos && (col+1 >= n || line[col+1] != '=')) {
637	                spans.push_back({0,(int)col,HL::KEYWORD});
638	            }
639	        }
640	
