662	        // Headings
663	        if (line[0] == '#') {
664	            size_t lvl = 0;
665	            while (lvl < n && line[lvl] == '#') ++lvl;
666	            static const int hcol[] = {HL::KEYWORD,HL::TYPE,HL::STRING,
667	                                        HL::NUMBER,HL::PREPROC,HL::COMMENT};
668	            spans.push_back({0,(int)n, hcol[std::min((int)lvl-1,5)]});
669	            return spans;
670	        }
671	        // Code fence
672	        if (n >= 3 && (line.substr(0,3)=="```"||line.substr(0,3)=="~~~")) {
673	            spans.push_back({0,(int)n,HL::STRING});
674	            return spans;
675	        }
676	        // Blockquote
677	        if (line[0] == '>') {
678	            spans.push_back({0,1,HL::COMMENT});
679	            i = 1;
680	        }
681	        // Horizontal rule: --- or *** (3+ same chars with optional spaces)
682	        {
683	            bool isHr = n >= 3;
684	            char c0 = line[0];
685	            if (isHr && (c0=='-'||c0=='*'||c0=='_')) {
686	                for (size_t j = 0; j < n; ++j)
687	                    if (line[j]!=c0 && line[j]!=' ') { isHr=false; break; }
688	                if (isHr) { spans.push_back({0,(int)n,HL::COMMENT}); return spans; }
689	            }
690	        }
691	
692	        while (i < n) {
693	            // Bold **text**
694	            if (i+1 < n && line[i]=='*' && line[i+1]=='*') {
695	                size_t start = i; i += 2;
696	                while (i+1 < n && !(line[i]=='*' && line[i+1]=='*')) ++i;
697	                if (i+1 < n) i += 2;
698	                spans.push_back({(int)start,(int)(i-start),HL::KEYWORD});
699	                continue;
700	            }
701	            // Italic *text*
702	            if (line[i]=='*' && i+1 < n && line[i+1]!='*' && line[i+1]!=' ') {
703	                size_t start = i++;
704	                while (i < n && !(line[i]=='*' && (i+1>=n||line[i+1]!='*'))) ++i;
705	                if (i < n) ++i;
706	                spans.push_back({(int)start,(int)(i-start),HL::TYPE});
707	                continue;
708	            }
709	            // Inline code `...`
710	            if (line[i] == '`') {
711	                size_t start = i++;
712	                while (i < n && line[i] != '`') ++i;
713	                if (i < n) ++i;
714	                spans.push_back({(int)start,(int)(i-start),HL::STRING});
715	                continue;
716	            }
717	            // Link [text](url)
718	            if (line[i] == '[') {
719	                size_t start = i++;
720	                while (i < n && line[i] != ']') ++i;
721	                if (i < n && i+1 < n && line[i+1] == '(') {
722	                    spans.push_back({(int)start,(int)(i-start+1),HL::KEYWORD});
723	                    i += 2;
724	                    size_t us = i;
725	                    while (i < n && line[i] != ')') ++i;
726	                    if (i < n) { spans.push_back({(int)us,(int)(i-us),HL::TYPE}); ++i; }
727	                }
