void Editor::refreshGit() {
    auto* buf = currentBuffer();
    std::string path = buf ? buf->filename() : filePanel_.currentPath();
    if (!path.empty()) {
        if (!repoInfo_.valid)
            repoInfo_ = git::detect(path);
