110	void Editor::doCloseCurrentBuffer() {
111	    if (buffers_.empty()) return;
112	    // persist cursor position before closing
113	    auto* buf = currentBuffer();
114	    if (buf && !buf->filename().empty())
115	        db_.savePosition(buf->filename(), buf->cursorRow(), buf->cursorCol());
116	    buffers_.erase(buffers_.begin() + currentBuf_);
117	    if (buffers_.empty()) { shouldQuit_ = true; return; }
118	    if (currentBuf_ >= (int)buffers_.size()) currentBuf_ = (int)buffers_.size() - 1;
119	}
120	
121	void Editor::switchBuffer(int idx) {
122	    if (idx >= 0 && idx < (int)buffers_.size()) currentBuf_ = idx;
123	}
124	
125	void Editor::nextBuffer() {
126	    if (!buffers_.empty()) currentBuf_ = (currentBuf_ + 1) % (int)buffers_.size();
127	}
128	
129	void Editor::prevBuffer() {
130	    if (!buffers_.empty())
131	        currentBuf_ = (currentBuf_ - 1 + (int)buffers_.size()) % (int)buffers_.size();
132	}
133	
134	// ── Rendering ──────────────────────────────────────────────────────────────
135	
136	void Editor::render() {
137	    std::string out;
138	    out.reserve(termRows_ * termCols_ * 4);
139	
140	    // Move to top-left, hide cursor during redraw
141	    out += "\033[H";
142	
143	    // --- Tabbar (row 0) ---
144	    out += "\033[44m\033[97m";  // bg blue, fg white
145	    int x = 0;
146	    for (int i = 0; i < (int)buffers_.size() && x < termCols_; ++i) {
147	        std::string label = " " + buffers_[i]->displayName();
148	        if (buffers_[i]->isDirty()) label += '*';
149	        label += ' ';
150	        int avail = termCols_ - x;
151	        if ((int)label.size() > avail) label.resize(avail);
152	
153	        if (i == currentBuf_) {
154	            out += "\033[0m\033[1m\033[47m\033[30m";  // bold, bg white, fg black
155	            out += label;
156	            out += "\033[0m\033[44m\033[97m";
157	        } else if (buffers_[i]->isDirty()) {
158	            out += "\033[33m" + label + "\033[97m";   // yellow for dirty
159	        } else {
160	            out += label;
161	        }
162	        x += (int)label.size();
163	    }
164	    // git info right-aligned in tabbar
165	    if (repoInfo_.valid) {
166	        std::string dot = repoInfo_.hasConflict ? "!" :
167	                          (repoInfo_.dirty || repoInfo_.hasStaged) ? "*" : " ";
168	        std::string gi = " " + repoInfo_.branch + dot;
169	        if (repoInfo_.ahead  > 0) gi += "↑" + std::to_string(repoInfo_.ahead);
170	        if (repoInfo_.behind > 0) gi += "↓" + std::to_string(repoInfo_.behind);
171	        gi += " ";
172	        int giLen = (int)gi.size();
173	        int fill  = termCols_ - x - giLen;
174	        if (fill > 0) out += std::string(fill, ' ');
175	        // colour the indicator
176	        if      (repoInfo_.hasConflict)              out += "\033[0m\033[41m\033[97m";
177	        else if (repoInfo_.dirty || repoInfo_.hasStaged) out += "\033[0m\033[43m\033[30m";
178	        else                                          out += "\033[0m\033[42m\033[30m";
179	        out += gi;
180	    } else {
181	        if (x < termCols_) out += std::string(termCols_ - x, ' ');
182	    }
183	    out += "\033[0m";
184	
185	    // --- Panel + Edit area (rows 1 .. termRows-2) ---
186	    for (int r = 0; r < editRows(); ++r) {
187	        // Position at start of this row
188	        out += "\033[" + std::to_string(r + 2) + ";1H";
189	
190	        // Panel column
191	        if (panelVisible_) {
192	            out += "\033[44m\033[97m";  // bg blue, fg white
193	            if (r == 0) {
194	                // header: current path
195	                out += pad(truncLeft(filePanel_.currentPath(), kPanelWidth), kPanelWidth);
196	            } else {
197	                const auto& entries = filePanel_.entries();
198	                int idx = filePanel_.scrollOffset() + (r - 1);
199	                if (idx < (int)entries.size()) {
200	                    const auto& entry = entries[idx];
201	                    bool isSel = (idx == filePanel_.selected()) && (mode_ == Mode::FilePanel);
202	
203	                    // git status marker (last char of kPanelWidth)
204	                    char gitMark = 0;
205	                    if (repoInfo_.valid && !fileGitStatus_.empty()) {
